//! Koa framework recognizer.
//!
//! Detects Koa apps paired with a router package and extracts route and
//! middleware registrations from the captured app/router surface.

use std::collections::HashMap;

use crate::cfg::ControlFlowGraph;
use crate::framework_recognizer::{
    FrameworkRecognizer, FrameworkTopology, HttpMethod, Middleware, Route,
};

pub struct KoaRecognizer;

impl FrameworkRecognizer for KoaRecognizer {
    fn framework_id(&self) -> &str {
        "koa"
    }

    fn language(&self) -> &str {
        "typescript"
    }

    fn detect(
        &self,
        source: &str,
        file_path: &str,
        cfgs: &[ControlFlowGraph],
    ) -> Option<FrameworkTopology> {
        let has_koa = source.contains("from 'koa'")
            || source.contains("from \"koa\"")
            || source.contains("require('koa')")
            || source.contains("require(\"koa\")");
        let has_router = source.contains("@koa/router") || source.contains("koa-router");

        if !has_koa || !has_router {
            return None;
        }

        let app_names = detect_koa_app_names(source);
        let mut router_prefixes = detect_koa_router_prefixes(source);
        let mut routes = Vec::new();
        let mut middleware = Vec::new();
        let mut middleware_order = 0;
        let lines: Vec<&str> = source.lines().collect();

        for (index, line) in lines.iter().enumerate() {
            let trimmed = line.trim();

            if let Some((router_name, parent_name, prefix)) = parse_router_group(trimmed) {
                let parent_prefix = router_prefixes
                    .get(parent_name.as_str())
                    .cloned()
                    .unwrap_or_default();
                router_prefixes.insert(router_name, join_paths(&parent_prefix, &prefix));
            }

            for app_name in &app_names {
                let use_pattern = format!("{}.use(", app_name);
                if trimmed.starts_with(&use_pattern)
                    && !trimmed.contains(".routes()")
                    && !trimmed.contains(".allowedMethods()")
                {
                    let name = extract_js_handler_name(&trimmed[use_pattern.len()..])
                        .or_else(|| find_callback_name(&lines, index + 1))
                        .unwrap_or_else(|| "koa_middleware".to_string());
                    middleware.push(Middleware {
                        name,
                        path_prefix: None,
                        handler_cfg_index: None,
                        order: middleware_order,
                    });
                    middleware_order += 1;
                }
            }

            for (router_name, prefix) in &router_prefixes {
                for (method_name, method) in &[
                    ("get", HttpMethod::Get),
                    ("post", HttpMethod::Post),
                    ("put", HttpMethod::Put),
                    ("delete", HttpMethod::Delete),
                    ("patch", HttpMethod::Patch),
                    ("all", HttpMethod::All),
                ] {
                    let pattern = format!("{}.{}(", router_name, method_name);
                    if let Some(start) = trimmed.find(&pattern) {
                        let after_paren = start + pattern.len();
                        if let Some(route_path) = extract_string_arg(&trimmed[after_paren..]) {
                            let path = join_paths(prefix, &route_path);
                            let handler_name = extract_js_handler_name(&trimmed[after_paren..])
                                .or_else(|| find_callback_name(&lines, index + 1))
                                .unwrap_or_else(|| {
                                    format!("{}_{}", method_name, sanitize_path(&path))
                                });
                            let handler_cfg_index = cfgs
                                .iter()
                                .position(|cfg| cfg.function_name == handler_name);

                            routes.push(Route {
                                method: method.clone(),
                                path,
                                handler_name,
                                handler_cfg_index,
                                source_start: 0,
                                source_end: 0,
                            });
                        }
                    }
                }

                let use_pattern = format!("{}.use(", router_name);
                if trimmed.starts_with(&use_pattern) {
                    let rest = &trimmed[use_pattern.len()..];
                    let path_prefix =
                        extract_string_arg(rest).map(|value| join_paths(prefix, &value));
                    let handler_name = extract_js_handler_name(rest)
                        .or_else(|| find_callback_name(&lines, index + 1))
                        .unwrap_or_else(|| "koa_router_middleware".to_string());
                    middleware.push(Middleware {
                        name: handler_name,
                        path_prefix,
                        handler_cfg_index: None,
                        order: middleware_order,
                    });
                    middleware_order += 1;
                }
            }
        }

        if routes.is_empty() {
            return None;
        }

        Some(FrameworkTopology {
            framework: "koa".to_string(),
            language: "typescript".to_string(),
            file_path: file_path.to_string(),
            routes,
            middleware,
            listen_port: detect_koa_port(source, &app_names),
            config: HashMap::new(),
        })
    }
}

fn detect_koa_app_names(source: &str) -> Vec<String> {
    let mut names = Vec::new();

    for line in source.lines() {
        let trimmed = line.trim();
        for prefix in &["const ", "let ", "var "] {
            if trimmed.starts_with(prefix) && trimmed.contains("= new Koa(") {
                if let Some(name) = trimmed
                    .strip_prefix(prefix)
                    .and_then(|rest| rest.split('=').next())
                    .map(|candidate| candidate.trim().to_string())
                {
                    if !name.is_empty() {
                        names.push(name);
                    }
                }
            }
        }
    }

    if names.is_empty() {
        names.push("app".to_string());
    }

    names
}

fn detect_koa_router_prefixes(source: &str) -> HashMap<String, String> {
    let mut prefixes = HashMap::new();

    for line in source.lines() {
        let trimmed = line.trim();
        for prefix in &["const ", "let ", "var "] {
            if trimmed.starts_with(prefix) && trimmed.contains("= new Router(") {
                let maybe_name = trimmed
                    .strip_prefix(prefix)
                    .and_then(|rest| rest.split('=').next())
                    .map(|candidate| candidate.trim().to_string());
                if let Some(name) = maybe_name {
                    let detected_prefix = trimmed
                        .find("prefix:")
                        .and_then(|index| extract_string_arg(&trimmed[index + "prefix:".len()..]))
                        .unwrap_or_default();
                    prefixes.insert(name, normalize_path(&detected_prefix));
                }
            }
        }
    }

    for line in source.lines() {
        let trimmed = line.trim();
        if let Some(prefix_call) = trimmed.find(".prefix(") {
            let name = trimmed[..prefix_call].trim();
            let path =
                extract_string_arg(&trimmed[prefix_call + ".prefix(".len()..]).unwrap_or_default();
            prefixes.insert(name.to_string(), normalize_path(&path));
        }
    }

    if prefixes.is_empty() {
        prefixes.insert("router".to_string(), "/".to_string());
    }

    prefixes
}

fn parse_router_group(line: &str) -> Option<(String, String, String)> {
    let group_index = line.find(".createRouter(")?;
    let router_name = line.split('=').next()?.trim().to_string();
    let parent_name = line[..group_index]
        .split('=')
        .nth(1)?
        .trim()
        .trim_end_matches(".createRouter")
        .to_string();
    let prefix = extract_string_arg(&line[group_index + ".createRouter(".len()..])?;
    Some((router_name, parent_name, prefix))
}

fn extract_string_arg(s: &str) -> Option<String> {
    let s = s.trim();
    let quote = s.chars().next()?;
    if quote != '\'' && quote != '"' && quote != '`' {
        return None;
    }
    let rest = &s[1..];
    let end = rest.find(quote)?;
    Some(rest[..end].to_string())
}

fn extract_js_handler_name(s: &str) -> Option<String> {
    let after_path = s.find(',')? + 1;
    let rest = s[after_path..].trim();
    if rest.starts_with('(') || rest.starts_with("async") || rest.starts_with("function") {
        return None;
    }
    let name: String = rest
        .chars()
        .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
        .collect();
    if name.is_empty() {
        None
    } else {
        Some(name)
    }
}

fn find_callback_name(lines: &[&str], start: usize) -> Option<String> {
    for line in lines.iter().skip(start) {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with('@') {
            continue;
        }
        if let Some(rest) = trimmed.strip_prefix("function ") {
            let name: String = rest
                .chars()
                .take_while(|c| c.is_alphanumeric() || *c == '_')
                .collect();
            if !name.is_empty() {
                return Some(name);
            }
        }
        break;
    }
    None
}

fn detect_koa_port(source: &str, app_names: &[String]) -> Option<u16> {
    for line in source.lines() {
        let trimmed = line.trim();
        for app_name in app_names {
            let pattern = format!("{}.listen(", app_name);
            if let Some(start) = trimmed.find(&pattern) {
                let num_str: String = trimmed[start + pattern.len()..]
                    .chars()
                    .take_while(|c| c.is_ascii_digit())
                    .collect();
                if let Ok(port) = num_str.parse::<u16>() {
                    return Some(port);
                }
            }
        }
    }
    None
}

fn normalize_path(value: &str) -> String {
    if value.is_empty() {
        return "/".to_string();
    }
    if value.starts_with('/') {
        value.to_string()
    } else {
        format!("/{value}")
    }
}

fn join_paths(prefix: &str, child: &str) -> String {
    let normalized_prefix = normalize_path(prefix).trim_end_matches('/').to_string();
    let normalized_child = normalize_path(child);
    if normalized_prefix == "/" {
        return normalized_child;
    }
    if normalized_child == "/" {
        return normalized_prefix;
    }
    format!("{}{}", normalized_prefix, normalized_child)
}

fn sanitize_path(path: &str) -> String {
    path.chars()
        .map(|c| if c.is_alphanumeric() { c } else { '_' })
        .collect::<String>()
        .trim_matches('_')
        .to_string()
}
